459	// C: #define next(ls)  (ls->current = zgetc(ls->z))
460	/// Advance the lexer by one character.
461	///
462	/// Corresponds to the `next(ls)` macro.  Named `advance` to avoid collision
463	/// with Rust's iterator method.
464	#[inline]
465	fn advance(ls: &mut LexState) {
466	    // C: ls->current = zgetc(ls->z)
467	    // macros.tsv: zgetc → z.getc()
468	    ls.current = ls.z.getc();
469	}
