471	// C: static void save (LexState *ls, int c) { ... }
472	/// Append character `c` to the token buffer, growing it if necessary.
473	///
474	/// On overflow calls [`lex_error`] which becomes `Err(LuaError::Syntax(...))`.
475	///
476	/// # C source
477	/// ```c
478	/// // C: static void save (LexState *ls, int c) {
479	/// //   Mbuffer *b = ls->buff;
480	/// //   if (luaZ_bufflen(b) + 1 > luaZ_sizebuffer(b)) {
481	/// //     size_t newsize;
482	/// //     if (luaZ_sizebuffer(b) >= MAX_SIZE/2)
483	/// //       lexerror(ls, "lexical element too long", 0);
484	/// //     newsize = luaZ_sizebuffer(b) * 2;
485	/// //     luaZ_resizebuffer(ls->L, b, newsize);
486	/// //   }
487	/// //   b->buffer[luaZ_bufflen(b)++] = cast_char(c);
488	/// // }
489	/// ```
490	fn save(ls: &mut LexState, state: &mut LuaState, c: i32) -> Result<(), LuaError> {
491	    // C: if (luaZ_bufflen(b) + 1 > luaZ_sizebuffer(b))
492	    // macros.tsv: luaZ_bufflen → buf.len(); luaZ_sizebuffer → buf.capacity()
493	    if ls.buff.len() + 1 > ls.buff.capacity() {
494	        // C: if (luaZ_sizebuffer(b) >= MAX_SIZE/2) lexerror(...)
495	        if ls.buff.capacity() >= MAX_SIZE / 2 {
496	            return Err(lex_error(ls, b"lexical element too long", 0));
497	        }
498	        // C: newsize = luaZ_sizebuffer(b) * 2;
499	        //    luaZ_resizebuffer(ls->L, b, newsize);
500	        // macros.tsv: luaZ_resizebuffer → buf.resize(state, size)?
501	        let newsize = ls.buff.capacity() * 2;
502	        ls.buff.resize(state, newsize)?;
503	    }
504	    // C: b->buffer[luaZ_bufflen(b)++] = cast_char(c);
505	    // macros.tsv: cast_char → x as i8  (C char is signed; Lua bytes stored as-is)
506	    // PORT NOTE: we store the byte value directly; the i8 cast in C is for the
507	    // C char type but the data is read back as unsigned via cast_uchar everywhere.
508	    ls.buff.push_byte(c as u8);
509	    Ok(())
510	}
