512	// C: #define save_and_next(ls) (save(ls, ls->current), next(ls))
513	/// Save the current character into the token buffer, then advance the stream.
514	///
515	/// Corresponds to the `save_and_next(ls)` macro.  Fallible because `save`
516	/// may need to grow the buffer.
517	#[inline]
518	fn save_and_next(ls: &mut LexState, state: &mut LuaState) -> Result<(), LuaError> {
519	    // C: save(ls, ls->current)
520	    let c = ls.current;
521	    save(ls, state, c)?;
522	    // C: next(ls)
523	    advance(ls);
524	    Ok(())
525	}
