529	// C: static l_noret lexerror (LexState *ls, const char *msg, int token)
530	// l_noret → -> !  but in Rust we return LuaError (callers wrap in Err(...))
531	// error_sites.tsv: luaX_lexerror → return Err(LuaError::syntax_at(ls, "msg", token))
532	/// Build a syntax error, optionally annotated with the offending token text.
533	///
534	/// Corresponds to the static `lexerror` function in `llex.c`.  In C this is
535	/// `l_noret` (diverges via `luaD_throw`); in Rust it returns a `LuaError`
536	/// value that callers wrap in `Err(...)`.
537	///
538	/// # C source
539	/// ```c
540	/// // C: static l_noret lexerror (LexState *ls, const char *msg, int token) {
541	/// //   msg = luaG_addinfo(ls->L, msg, ls->source, ls->linenumber);
542	/// //   if (token)
543	/// //     luaO_pushfstring(ls->L, "%s near %s", msg, txtToken(ls, token));
544	/// //   luaD_throw(ls->L, LUA_ERRSYNTAX);
545	/// // }
546	/// ```
547	fn lex_error(ls: &mut LexState, msg: &[u8], token: i32) -> LuaError {
548	    // C: msg = luaG_addinfo(ls->L, msg, ls->source, ls->linenumber);
549	    // TODO(port): call lua_vm::debug::add_info(msg, &ls.source, ls.linenumber)
550	    // to prepend "<source>:<line>: " prefix.  For Phase A, build it manually:
551	    let mut full_msg: Vec<u8> = Vec::new();
552	    let _ = write!(full_msg, "{}:{}: ", "<source>", ls.linenumber);
553	    full_msg.extend_from_slice(msg);
554	
555	    // C: if (token) luaO_pushfstring(ls->L, "%s near %s", msg, txtToken(ls, token));
556	    if token != 0 {
557	        let tok_text = txt_token(ls, token);
558	        full_msg.extend_from_slice(b" near ");
559	        full_msg.extend_from_slice(&tok_text);
560	    }
561	
562	    // C: luaD_throw(ls->L, LUA_ERRSYNTAX);
563	    // error_sites.tsv: → LuaError::syntax(...)
564	    // TODO(port): LuaError::syntax(format_args!(...)) once LuaError is wired;
565	    // for Phase A return a placeholder via the stub LuaError type.
566	    LuaError::syntax_raw(&full_msg)
567	}
