629	// C: const char *luaX_token2str (LexState *ls, int token)
630	// LUAI_FUNC → pub(crate)
631	/// Produce a human-readable token description (for error messages and the parser).
632	///
633	/// Single-byte printable tokens are formatted as `'X'`; non-printable as
634	/// `'<\N>'`.  Reserved words and multi-char symbols are formatted as `'kw'`.
635	/// Literal tokens (`<name>`, `<string>`, etc.) return the bare label.
636	///
637	/// # C source
638	/// ```c
639	/// // C: const char *luaX_token2str (LexState *ls, int token) {
640	/// //   if (token < FIRST_RESERVED) {
641	/// //     if (lisprint(token))
642	/// //       return luaO_pushfstring(ls->L, "'%c'", token);
643	/// //     else
644	/// //       return luaO_pushfstring(ls->L, "'<\\%d>'", token);
645	/// //   }
646	/// //   else {
647	/// //     const char *s = luaX_tokens[token - FIRST_RESERVED];
648	/// //     if (token < TK_EOS)
649	/// //       return luaO_pushfstring(ls->L, "'%s'", s);
650	/// //     else
651	/// //       return s;
652	/// //   }
653	/// // }
654	/// ```
655	///
656	/// PORT NOTE: The `LexState` parameter is retained in the signature for API
657	/// parity with the C export, but is unused in Rust because we don't push onto
658	/// the Lua stack.  The real formatting is in [`token2str_raw`].
659	pub(crate) fn token2str(_ls: &LexState, token: i32) -> Vec<u8> {
660	    token2str_raw(token)
661	}
662	
663	/// Inner implementation of [`token2str`] that does not need `LexState`.
664	fn token2str_raw(token: i32) -> Vec<u8> {
665	    if token < FIRST_RESERVED {
666	        // C: if (lisprint(token)) return "'%c'"; else return "'<\\%d>'"
667	        if is_print(token) {
668	            // C: luaO_pushfstring(ls->L, "'%c'", token)
669	            vec![b'\'', token as u8, b'\'']
670	        } else {
671	            // C: luaO_pushfstring(ls->L, "'<\\%d>'", token)
672	            // PORT NOTE: uses write! to Vec<u8> to avoid String allocation for Lua data.
673	            let mut v: Vec<u8> = Vec::new();
674	            v.extend_from_slice(b"'<\\");
675	            let _ = write!(&mut v, "{}", token);
676	            v.extend_from_slice(b">'");
677	            v
678	        }
679	    } else {
680	        let idx = (token - FIRST_RESERVED) as usize;
681	        let s = LUAX_TOKENS[idx];
682	        if token < TK_EOS {
683	            // C: luaO_pushfstring(ls->L, "'%s'", s)  — wrap in single quotes
684	            let mut v: Vec<u8> = Vec::with_capacity(s.len() + 2);
685	            v.push(b'\'');
686	            v.extend_from_slice(s);
687	            v.push(b'\'');
688	            v
689	        } else {
690	            // C: return s  — bare label like "<name>", "<eof>"
691	            s.to_vec()
692	        }
693	    }
694	}
