/// C: static void init_exp(expdesc *e, expkind k, int i)
fn init_exp(e: &mut ExprDesc, k: ExprKind, i: i32) {
    e.f = NO_JUMP;
    e.t = NO_JUMP;
    e.k = k;
    e.u.info = i;
}

/// C: static void codestring(expdesc *e, TString *s)
fn codestring(e: &mut ExprDesc, s: GcRef<LuaString>) {
