fn adjust_assign(
    ls: &mut LexState,
    state: &mut LuaState,
    nvars: i32,
    nexps: i32,
    e: &mut ExprDesc,
) -> Result<(), LuaError> {
    let needed = nvars - nexps;
    let fs = ls.fs.as_mut().unwrap();
    if e.k.has_mult_ret() {
