    // TODO(port): lua_code::indexed(ls.fs.as_mut().unwrap(), v, &mut key)?;
    Ok(())
}

/// C: static void yindex(LexState *ls, expdesc *v)
/// Handles '[' expr ']' indexing.
fn yindex(ls: &mut LexState, state: &mut LuaState, v: &mut ExprDesc) -> Result<(), LuaError> {
